#include <stdio.h>

struct Point {
    int x;
    int y;
};

int main() {
    struct Point p1 = {10, 20};
    printf("x: %d, y: %d\n", p1.x, p1.y);
    return 0;
}

#include <stdio.h>

struct Book {
    char title[50];
    float price;
};

int main() {
    struct Book library[3] = {
        {"C Prog", 20.5},
        {"Algorithms", 50.0},
        {"OS", 30.0}
    };
    for(int i=0; i<3; i++) {
        printf("%s: $%.2f\n", library[i].title, library[i].price);
    }
    return 0;
}

#include <stdio.h>

struct Person {
    int age;
};

int main() {
    struct Person p1 = {25};
    struct Person *ptr = &p1;
    printf("Age: %d\n", ptr->age);
    return 0;
}

#include <stdio.h>

typedef struct Employee {
    int id;
    char name[20];
} s_emp;

int main() {
    s_emp e1 = {101, "Alice"};
    printf("ID: %d\n", e1.id);
    return 0;
}

#include <stdio.h>

struct Date {
    int day, month, year;
};

struct Student {
    char name[20];
    struct Date dob;
};

int main() {
    struct Student s = {"Bob", {15, 8, 2000}};
    printf("Birth Year: %d\n", s.dob.year);
    return 0;
}

#include <stdio.h>

union Data {
    int i;
    float f;
};

int main() {
    union Data data;
    data.i = 10;
    printf("i: %d\n", data.i);
    data.f = 220.5;
    printf("f: %.1f\n", data.f);
    printf("i: %d (garbage)\n", data.i); // i is now corrupted
    return 0;
}

#include <stdio.h>

typedef struct {
    int x, y;
} Point;

void printPoint(Point p) {
    printf("(%d, %d)\n", p.x, p.y);
}

int main() {
    Point p1 = {5, 10};
    printPoint(p1);
    return 0;
}

